// ── Questions ─────────────────────────────────────────────────────────────
// id, topic, stem, options {A-E}, answer (letter), explanation

const QUESTIONS = [

// ══ ANTIBIOTICS (18) ══════════════════════════════════════════════════════
{id:"q001",topic:"Antibiotics",stem:"A 28-year-old woman has a lower UTI. Not pregnant, recurrent infections. Which antibiotic is first line?",options:{A:"Amoxicillin",B:"Trimethoprim",C:"Ciprofloxacin",D:"Co-amoxiclav",E:"Metronidazole"},answer:"B",explanation:"Trimethoprim is first line for uncomplicated lower UTIs — inhibits dihydrofolate reductase, blocking bacterial folate synthesis. Nitrofurantoin is an alternative. Ciprofloxacin is reserved for complicated UTIs."},
{id:"q002",topic:"Antibiotics",stem:"A patient with known penicillin allergy develops community-acquired pneumonia with atypical features. Best antibiotic?",options:{A:"Amoxicillin",B:"Ceftriaxone",C:"Clarithromycin",D:"Metronidazole",E:"Gentamicin"},answer:"C",explanation:"Clarithromycin (macrolide) covers atypical organisms — Mycoplasma, Legionella, Chlamydophila — and is safe in penicillin allergy. It binds the 50S ribosomal subunit."},
{id:"q003",topic:"Antibiotics",stem:"A patient with MRSA bacteraemia needs IV treatment. Drug of choice?",options:{A:"Flucloxacillin",B:"Amoxicillin",C:"Vancomycin",D:"Co-amoxiclav",E:"Ciprofloxacin"},answer:"C",explanation:"Vancomycin is the go-to for MRSA. It binds D-Ala D-Ala on peptidoglycan precursors, blocking cell wall synthesis. Flucloxacillin only covers MSSA."},
{id:"q004",topic:"Antibiotics",stem:"A patient on rifampicin for TB also takes the oral contraceptive pill. Key concern?",options:{A:"Rifampicin causes gynaecomastia",B:"Rifampicin induces CYP450, reducing OCP effectiveness",C:"Rifampicin is nephrotoxic",D:"Rifampicin blocks oestrogen receptors",E:"Rifampicin causes QT prolongation"},answer:"B",explanation:"Rifampicin is a powerful CYP450 inducer — speeds up metabolism of the OCP (and HIV drugs), reducing their plasma levels. The patient needs additional contraception."},
{id:"q005",topic:"Antibiotics",stem:"A 45-year-old man has a dental abscess. He is a social drinker. He's prescribed an antibiotic with a specific alcohol interaction. Which drug?",options:{A:"Amoxicillin",B:"Clarithromycin",C:"Metronidazole",D:"Doxycycline",E:"Trimethoprim"},answer:"C",explanation:"Metronidazole causes a disulfiram-like reaction with alcohol — severe nausea, flushing, palpitations. Always warn patients to avoid alcohol completely during and 48h after course."},
{id:"q006",topic:"Antibiotics",stem:"Gentamicin is prescribed for a severe Gram-negative infection. Which two side effects require close monitoring?",options:{A:"Hepatotoxicity and rash",B:"Nephrotoxicity and ototoxicity",C:"Peripheral neuropathy and QT prolongation",D:"Aplastic anaemia and grey baby syndrome",E:"Red man syndrome and nephrotoxicity"},answer:"B",explanation:"Gentamicin (aminoglycoside) causes nephrotoxicity and ototoxicity — hearing loss and vestibular damage. Monitor trough AND peak levels; narrow therapeutic index."},
{id:"q007",topic:"Antibiotics",stem:"A patient has cellulitis caused by MSSA. Antibiotic of choice?",options:{A:"Vancomycin",B:"Metronidazole",C:"Ceftriaxone",D:"Flucloxacillin",E:"Ciprofloxacin"},answer:"D",explanation:"Flucloxacillin is drug of choice for MSSA skin infections. It's a penicillinase-resistant penicillin — not broken down by staph beta-lactamase."},
{id:"q008",topic:"Antibiotics",stem:"A patient on doxycycline for acne asks about side effects. Most important counselling point?",options:{A:"Avoid dairy with each dose",B:"Avoid sunlight — photosensitivity risk",C:"Avoid all exercise",D:"Take on an empty stomach only",E:"Avoid fruit juice"},answer:"B",explanation:"Photosensitivity is a key tetracycline side effect — use high SPF sunscreen. Also avoid in children <12 (teeth discolouration/bone growth) and pregnancy."},
{id:"q009",topic:"Antibiotics",stem:"A patient has Clostridioides difficile colitis. Which treatment is first line for a severe episode?",options:{A:"Amoxicillin",B:"Oral vancomycin",C:"IV gentamicin",D:"Rifampicin",E:"Nitrofurantoin"},answer:"B",explanation:"Oral vancomycin is first line for severe C. diff. It's not absorbed from the gut — stays locally active in the colon. Fidaxomicin is an alternative. Metronidazole for mild cases only."},
{id:"q010",topic:"Antibiotics",stem:"Chloramphenicol eye drops are used for bacterial conjunctivitis. Most feared side effect of systemic chloramphenicol?",options:{A:"Nephrotoxicity",B:"Ototoxicity",C:"Aplastic anaemia",D:"Red man syndrome",E:"QT prolongation"},answer:"C",explanation:"Systemic chloramphenicol causes idiosyncratic aplastic anaemia (irreversible) and grey baby syndrome in neonates — immature glucuronyl transferase cannot conjugate the drug."},
{id:"q011",topic:"Antibiotics",stem:"What is the mechanism of beta-lactam resistance in MRSA?",options:{A:"Efflux pumps remove the drug",B:"Beta-lactamase breaks down the ring",C:"Modified penicillin-binding proteins (mecA gene)",D:"Reduced cell wall permeability",E:"Altered ribosome binding site"},answer:"C",explanation:"MRSA has modified PBPs encoded by the mecA gene — beta-lactams cannot bind to block transpeptidase. That's why vancomycin (different target: D-Ala D-Ala) works."},
{id:"q012",topic:"Antibiotics",stem:"You suspect Pseudomonas infection in a hospitalised patient. Which antibiotic has good Pseudomonal coverage?",options:{A:"Amoxicillin",B:"Trimethoprim",C:"Ciprofloxacin",D:"Clarithromycin",E:"Metronidazole"},answer:"C",explanation:"Ciprofloxacin (quinolone) is one of the few oral antibiotics with good anti-pseudomonal activity. IV options include piperacillin-tazobactam and meropenem."},
{id:"q013",topic:"Antibiotics",stem:"A 30-year-old has Lyme disease. Preferred first-line oral antibiotic?",options:{A:"Vancomycin",B:"Doxycycline",C:"Flucloxacillin",D:"Metronidazole",E:"Nitrofurantoin"},answer:"B",explanation:"Doxycycline is first-line for Lyme disease (Borrelia burgdorferi). Amoxicillin is used in children and pregnancy. Duration is typically 10–21 days depending on stage."},
{id:"q014",topic:"Antibiotics",stem:"A patient develops 'red man syndrome' during a vancomycin infusion. What caused this?",options:{A:"IgE-mediated type I hypersensitivity",B:"Complement activation",C:"Non-immune mast cell degranulation due to rapid infusion",D:"Direct cytotoxicity",E:"Type IV delayed hypersensitivity"},answer:"C",explanation:"Red man syndrome is NOT a true allergy — it's caused by non-immune mast cell degranulation if vancomycin is infused too quickly, releasing histamine. Slowing the infusion rate prevents it."},
{id:"q015",topic:"Antibiotics",stem:"A patient with PCP (Pneumocystis pneumonia) needs treatment. Which drug?",options:{A:"Amoxicillin",B:"Metronidazole",C:"Co-trimoxazole (trimethoprim + sulfamethoxazole)",D:"Flucloxacillin",E:"Rifampicin"},answer:"C",explanation:"Co-trimoxazole (TMP-SMX) is first-line for PCP. It's also used as prophylaxis in immunocompromised patients (CD4 <200 in HIV). PCP does not respond to standard antibiotics."},
{id:"q016",topic:"Antibiotics",stem:"A pregnant woman at 32 weeks has asymptomatic bacteriuria caused by E. coli. Safe treatment?",options:{A:"Trimethoprim",B:"Ciprofloxacin",C:"Cefalexin",D:"Doxycycline",E:"Nitrofurantoin after 36 weeks"},answer:"C",explanation:"Cefalexin (cephalosporin) is safe in pregnancy. Trimethoprim is avoided in 1st trimester (folate antagonist). Ciprofloxacin/doxycycline are contraindicated. Nitrofurantoin avoided near term (neonatal haemolysis risk)."},
{id:"q017",topic:"Antibiotics",stem:"Macrolide antibiotics like erythromycin frequently cause which GI side effect?",options:{A:"Constipation",B:"Acute liver failure",C:"Nausea, vomiting and abdominal cramps",D:"Bloody diarrhoea",E:"Pancreatitis"},answer:"C",explanation:"Macrolides are motilin receptor agonists — they stimulate gut motility, causing nausea, vomiting and abdominal cramps. This is the most common reason patients stop erythromycin. Azithromycin is better tolerated."},
{id:"q018",topic:"Antibiotics",stem:"A patient on warfarin is prescribed a short course of metronidazole for a dental infection. What happens to their INR?",options:{A:"INR decreases — metronidazole induces CYP2C9",B:"INR increases — metronidazole inhibits CYP2C9, reducing warfarin metabolism",C:"No effect on INR",D:"INR becomes unpredictable only",E:"Metronidazole directly activates clotting"},answer:"B",explanation:"Metronidazole inhibits CYP2C9 — the main enzyme metabolising warfarin S-enantiomer. This causes warfarin accumulation and INR to rise dangerously. Monitor INR closely and consider dose reduction."},

// ══ CARDIOVASCULAR (20) ═══════════════════════════════════════════════════
{id:"q019",topic:"Cardiovascular",stem:"A 58-year-old on lisinopril develops a persistent dry cough. Best management?",options:{A:"Add codeine to suppress cough",B:"Switch to candesartan (ARB)",C:"Add a beta blocker",D:"Switch to amlodipine",E:"Add furosemide"},answer:"B",explanation:"ACE inhibitors cause cough via bradykinin accumulation. ARBs (candesartan, losartan) block AT1 receptors without affecting bradykinin — no cough side effect."},
{id:"q020",topic:"Cardiovascular",stem:"A patient on warfarin has an INR of 8 after dental surgery. What reverses it?",options:{A:"Fresh frozen plasma only",B:"Vitamin K (phytomenadione)",C:"Protamine sulfate",D:"Naloxone",E:"Atropine"},answer:"B",explanation:"Vitamin K restores synthesis of clotting factors II, VII, IX, X by gamma-carboxylation. FFP provides immediate factor replacement for life-threatening bleeds alongside vitamin K."},
{id:"q021",topic:"Cardiovascular",stem:"A patient with acute STEMI receives aspirin. Mechanism?",options:{A:"Activates plasminogen",B:"Irreversibly inhibits COX-1 → reduces TXA2 → less platelet aggregation",C:"Blocks P2Y12 receptor",D:"Inhibits Factor Xa directly",E:"Blocks GPIIb/IIIa receptor"},answer:"B",explanation:"Aspirin irreversibly inhibits COX-1, reducing thromboxane A2 — which normally promotes platelet aggregation and vasoconstriction. Even low-dose aspirin achieves full antiplatelet effect."},
{id:"q022",topic:"Cardiovascular",stem:"A 72-year-old with heart failure starts spironolactone. Key electrolyte risk?",options:{A:"Hypokalaemia",B:"Hypercalcaemia",C:"Hyperkalaemia",D:"Hyponatraemia",E:"Hypernatraemia"},answer:"C",explanation:"Spironolactone is an aldosterone antagonist — retains K+. Risk of hyperkalaemia, especially when combined with ACE inhibitors or ARBs. Check renal function and K+ at baseline and after 1 week."},
{id:"q023",topic:"Cardiovascular",stem:"A patient with AF needs rate control. Which CCB is appropriate?",options:{A:"Amlodipine",B:"Nifedipine",C:"Verapamil",D:"Felodipine",E:"Lercanidipine"},answer:"C",explanation:"Verapamil and diltiazem are rate-limiting CCBs — they slow AV conduction. Dihydropyridines (amlodipine, nifedipine) mainly vasodilate and do not slow heart rate — can actually increase it reflexly."},
{id:"q024",topic:"Cardiovascular",stem:"A patient takes sublingual GTN for angina. No relief after 5 minutes. Next step?",options:{A:"Give another dose; call 999 if no relief after further 5 min",B:"Wait 30 more minutes",C:"Give oral isosorbide mononitrate",D:"Give IV furosemide",E:"Start warfarin"},answer:"A",explanation:"GTN protocol: first dose → wait 5 min → if no relief give second dose → wait 5 min → if still no relief call 999 (potential ACS). GTN is a nitrate — releases NO → venodilation → reduced preload."},
{id:"q025",topic:"Cardiovascular",stem:"Amiodarone causes thyroid dysfunction. Why?",options:{A:"Blocks TSH receptors",B:"Contains iodine and inhibits T4→T3 conversion",C:"Activates glucocorticoid receptors",D:"Hepatotoxicity disrupts thyroid metabolism",E:"Blocks beta receptors in the thyroid"},answer:"B",explanation:"Amiodarone is 37% iodine by weight. It inhibits T4→T3 conversion and can cause both hypo- and hyperthyroidism. Also causes pulmonary fibrosis, corneal microdeposits, photosensitivity. Extensive monitoring needed."},
{id:"q026",topic:"Cardiovascular",stem:"Classic visual symptom of digoxin toxicity?",options:{A:"Red-green colour blindness",B:"Yellow-green visual halos around lights",C:"Diplopia",D:"Complete blindness",E:"Flashing lights only"},answer:"B",explanation:"Digoxin toxicity causes xanthopsia — yellow-green visual halos. Other signs: bradycardia, heart block, nausea, vomiting. Narrow therapeutic index (0.5–2 nmol/L). Hypokalaemia potentiates toxicity."},
{id:"q027",topic:"Cardiovascular",stem:"Furosemide is given for acute pulmonary oedema. Mechanism?",options:{A:"Inhibits Na/Cl symporter in distal tubule",B:"Inhibits Na/K/2Cl cotransporter in loop of Henle",C:"Blocks aldosterone receptor",D:"Inhibits carbonic anhydrase",E:"Blocks aquaporins"},answer:"B",explanation:"Furosemide is a loop diuretic — inhibits Na/K/2Cl cotransporter in thick ascending loop of Henle → powerful diuresis. Risks: hypokalaemia, dehydration, ototoxicity (especially with aminoglycosides)."},
{id:"q028",topic:"Cardiovascular",stem:"A patient on atorvastatin complains of muscle pain. First investigation?",options:{A:"Troponin",B:"Creatine kinase (CK)",C:"LFTs and bilirubin",D:"Thyroid function",E:"FBC"},answer:"B",explanation:"Statins can cause myopathy/rhabdomyolysis — check CK. If >10x upper limit, stop the statin. Also check TFTs (hypothyroidism predisposes to statin myopathy). Risk increased by fibrates, ciclosporin, macrolides."},
{id:"q029",topic:"Cardiovascular",stem:"Which antiplatelet requires CYP2C19 activation to work?",options:{A:"Aspirin",B:"Ticagrelor",C:"Clopidogrel",D:"Abciximab",E:"Dipyridamole"},answer:"C",explanation:"Clopidogrel is a prodrug requiring CYP2C19 activation. Poor metabolisers (common in East Asian populations) get inadequate platelet inhibition. Ticagrelor is a direct-acting P2Y12 inhibitor — no activation needed."},
{id:"q030",topic:"Cardiovascular",stem:"A 67-year-old with AF and mild heart failure needs rate control. Most appropriate drug?",options:{A:"Bisoprolol alone",B:"Verapamil alone",C:"Digoxin",D:"Propranolol",E:"Amlodipine"},answer:"C",explanation:"Digoxin slows AV conduction AND has positive inotropic effects — useful when AF coexists with heart failure. Beta-blockers can worsen acute HF. Verapamil is negatively inotropic — avoid in HF."},
{id:"q031",topic:"Cardiovascular",stem:"A patient with T2DM and heart failure benefits from which drug class for BOTH conditions?",options:{A:"Sulfonylurea",B:"GLP-1 agonist",C:"SGLT2 inhibitor",D:"DPP-4 inhibitor",E:"Thiazolidinedione"},answer:"C",explanation:"SGLT2 inhibitors (empagliflozin, dapagliflozin) have proven benefit in both T2DM glycaemic control AND heart failure mortality reduction (EMPEROR-Reduced, DAPA-HF trials)."},
{id:"q032",topic:"Cardiovascular",stem:"Heparin reversal in emergency. Which drug?",options:{A:"Vitamin K",B:"Protamine sulfate",C:"Tranexamic acid",D:"Idarucizumab",E:"Andexanet alfa"},answer:"B",explanation:"Protamine sulfate reverses heparin — it's a positively charged protein that binds negatively charged heparin, forming an inactive complex. 1mg protamine per 100 units heparin. Only partially reverses LMWH."},
{id:"q033",topic:"Cardiovascular",stem:"A patient on warfarin needs emergency surgery in 2 hours. INR is 4.2. Fastest reversal?",options:{A:"Vitamin K 10mg IV",B:"Stop warfarin and wait",C:"4-factor prothrombin complex concentrate (PCC)",D:"Fresh frozen plasma alone",E:"Protamine sulfate"},answer:"C",explanation:"4-factor PCC (contains factors II, VII, IX, X) provides immediate reversal within minutes. FFP takes longer and needs large volumes. IV vitamin K works over hours, not minutes. PCC + IV vitamin K together for urgent surgery."},
{id:"q034",topic:"Cardiovascular",stem:"A patient with hypertension and gout — which antihypertensive should be AVOIDED?",options:{A:"Amlodipine",B:"Losartan",C:"Bendroflumethiazide",D:"Doxazosin",E:"Methyldopa"},answer:"C",explanation:"Thiazide diuretics (bendroflumethiazide, indapamide) raise uric acid — they compete with urate for tubular secretion. Contraindicated in gout. Losartan is actually uricosuric — preferred in gout + hypertension."},
{id:"q035",topic:"Cardiovascular",stem:"Which class of antiarrhythmic blocks sodium channels and is used for VT/VF?",options:{A:"Class II — beta blockers",B:"Class III — potassium channel blockers",C:"Class IV — calcium channel blockers",D:"Class I — sodium channel blockers",E:"Class V — digoxin"},answer:"D",explanation:"Class I antiarrhythmics (lidocaine, flecainide, propafenone) block Na+ channels, reducing phase 0 depolarisation. Lidocaine IV is used for VT. Flecainide for paroxysmal AF but avoid post-MI (CAST trial)."},
{id:"q036",topic:"Cardiovascular",stem:"A patient on dabigatran (direct thrombin inhibitor) has life-threatening bleeding. Reversal agent?",options:{A:"Vitamin K",B:"Protamine sulfate",C:"Idarucizumab",D:"Andexanet alfa",E:"Tranexamic acid"},answer:"C",explanation:"Idarucizumab is the specific reversal agent for dabigatran — it's a monoclonal antibody fragment that binds dabigatran with very high affinity. Andexanet alfa reverses Factor Xa inhibitors (rivaroxaban, apixaban)."},
{id:"q037",topic:"Cardiovascular",stem:"A 45-year-old with hypertension is started on ramipril. What should be checked at 1–2 weeks?",options:{A:"FBC and platelets",B:"Urea, creatinine, electrolytes",C:"LFTs",D:"Thyroid function",E:"Blood glucose"},answer:"B",explanation:"ACE inhibitors can cause AKI (especially with renal artery stenosis) and hyperkalaemia. Check U&E at baseline, 1–2 weeks after starting, and after any dose increase. Rise in creatinine up to 30% is acceptable."},
{id:"q038",topic:"Cardiovascular",stem:"Beta-blocker overdose with bradycardia and hypotension. Drug of choice?",options:{A:"Adrenaline",B:"Atropine then glucagon",C:"Digoxin",D:"Calcium gluconate",E:"Amiodarone"},answer:"B",explanation:"For beta-blocker OD: atropine (blocks vagal tone) as first-line, then glucagon (bypasses blocked beta receptors, increases cAMP directly). High-dose insulin euglycaemic therapy is also used. Calcium is for CCB OD."},

// ══ RESPIRATORY (12) ══════════════════════════════════════════════════════
{id:"q039",topic:"Respiratory",stem:"A child with severe acute asthma arrives in A&E. First bronchodilator?",options:{A:"Salmeterol inhaler",B:"Tiotropium inhaler",C:"Salbutamol nebuliser",D:"Theophylline IV",E:"Beclomethasone"},answer:"C",explanation:"Salbutamol (SABA) nebulised is first-line in acute asthma. Ipratropium nebuliser can be added for severe/life-threatening attacks. Salmeterol is a LABA — never use for acute attacks."},
{id:"q040",topic:"Respiratory",stem:"A patient using beclomethasone inhaler develops white oral patches. Cause and prevention?",options:{A:"Bacterial superinfection — antibiotics needed",B:"Drug-induced mucositis — dose reduction",C:"Oral candidiasis from inhaled corticosteroid — rinse mouth after use",D:"Allergic reaction — stop inhaler",E:"Aphthous ulcers — unrelated to inhaler"},answer:"C",explanation:"Inhaled corticosteroids cause oral candidiasis from local immunosuppression. Counsel: rinse mouth and gargle after EVERY use. A spacer device reduces oropharyngeal deposition."},
{id:"q041",topic:"Respiratory",stem:"A COPD patient on salbutamol PRN still has frequent exacerbations. Next step in maintenance?",options:{A:"Add senna",B:"Add tiotropium (LAMA)",C:"Switch to IV theophylline",D:"Add metformin",E:"Add furosemide"},answer:"B",explanation:"COPD stepwise: SABA → add LAMA (tiotropium) or LABA. Tiotropium blocks M3 muscarinic receptors → sustained bronchodilation. Reduces exacerbation frequency. Add ICS only if frequent exacerbations + FEV1 <50%."},
{id:"q042",topic:"Respiratory",stem:"Which beta blocker must be AVOIDED in asthma?",options:{A:"Bisoprolol",B:"Atenolol",C:"Propranolol",D:"Metoprolol",E:"Nebivolol"},answer:"C",explanation:"Propranolol is non-selective (β1+β2) — blocks β2 in lungs → bronchoconstriction. If a beta-blocker is essential in asthma, use a cardioselective β1 blocker (bisoprolol) with caution."},
{id:"q043",topic:"Respiratory",stem:"A patient on theophylline quits smoking. What happens to theophylline levels?",options:{A:"Decreases — dose needs reducing",B:"Stays the same",C:"Increases — risk of toxicity",D:"Becomes inactive",E:"Excreted faster"},answer:"C",explanation:"Smoking induces CYP1A2, speeding theophylline metabolism. Quitting reduces induction → theophylline accumulates → risk of toxicity (seizures, arrhythmias, nausea). Reduce the dose when a patient stops smoking."},
{id:"q044",topic:"Respiratory",stem:"Montelukast is prescribed for asthma. Mechanism?",options:{A:"Beta-2 receptor agonist",B:"Muscarinic antagonist",C:"Cysteinyl leukotriene (CysLT1) receptor antagonist",D:"Corticosteroid",E:"Phosphodiesterase inhibitor"},answer:"C",explanation:"Montelukast blocks CysLT1 receptors — leukotrienes cause bronchoconstriction and inflammation in asthma. Particularly useful in aspirin-exacerbated asthma and exercise-induced asthma. Added to ICS if uncontrolled on step 2."},
{id:"q045",topic:"Respiratory",stem:"A patient with severe COPD is started on roflumilast. Mechanism?",options:{A:"Beta-2 agonist",B:"Muscarinic antagonist",C:"PDE4 inhibitor → reduces inflammation",D:"Leukotriene antagonist",E:"Mast cell stabiliser"},answer:"C",explanation:"Roflumilast is a selective PDE4 inhibitor — increases cAMP in inflammatory cells → anti-inflammatory effect. Used for severe COPD with frequent exacerbations (FEV1 <50%, chronic bronchitis phenotype). Side effects: nausea, weight loss."},
{id:"q046",topic:"Respiratory",stem:"A patient develops allergic rhinitis. Which intranasal preparation is most effective for long-term control?",options:{A:"Intranasal decongestant (xylometazoline)",B:"Intranasal corticosteroid (fluticasone)",C:"Oral antihistamine alone",D:"Intranasal cromoglicate only",E:"Intranasal adrenaline"},answer:"B",explanation:"Intranasal corticosteroids (fluticasone, mometasone) are most effective for persistent allergic rhinitis — reduce mucosal inflammation. Oral antihistamines help with itch/sneezing but less effective for nasal blockage. Avoid prolonged decongestant use (rhinitis medicamentosa)."},
{id:"q047",topic:"Respiratory",stem:"Ipratropium bromide — mechanism in COPD?",options:{A:"Long-acting beta-2 agonist",B:"Short-acting muscarinic antagonist (SAMA) → bronchodilation",C:"Inhibits leukotriene synthesis",D:"Corticosteroid",E:"Phosphodiesterase inhibitor"},answer:"B",explanation:"Ipratropium is a SAMA — blocks M3 muscarinic receptors on smooth muscle → bronchodilation. Short-acting; used for acute COPD exacerbations alongside salbutamol. Tiotropium is the long-acting equivalent (LAMA)."},
{id:"q048",topic:"Respiratory",stem:"Omalizumab is used in severe allergic asthma. Target?",options:{A:"IL-5",B:"IL-4 receptor",C:"IgE",D:"TNF-alpha",E:"IL-13"},answer:"C",explanation:"Omalizumab is a monoclonal antibody that binds free IgE, preventing it from triggering mast cell degranulation. Used in severe persistent allergic asthma uncontrolled on high-dose ICS + LABA. Requires positive skin prick test."},
{id:"q049",topic:"Respiratory",stem:"A patient with CF has a Pseudomonas chest infection. What inhaled treatment is added long-term?",options:{A:"Inhaled vancomycin",B:"Inhaled tobramycin or colistin",C:"Inhaled fluconazole",D:"Inhaled salmeterol only",E:"Inhaled rifampicin"},answer:"B",explanation:"In CF, chronic Pseudomonas aeruginosa colonisation is managed with inhaled tobramycin (TOBI) or colistin — delivering high concentrations directly to the airways while limiting systemic toxicity."},
{id:"q050",topic:"Respiratory",stem:"Magnesium sulphate IV is given in acute severe asthma. Mechanism?",options:{A:"Beta-2 agonist activity",B:"Blocks leukotriene synthesis",C:"Smooth muscle relaxation via calcium channel inhibition",D:"Reduces airway inflammation",E:"Enhances salbutamol receptor binding"},answer:"C",explanation:"IV magnesium sulphate is used in acute severe or life-threatening asthma unresponsive to bronchodilators. It causes smooth muscle relaxation by blocking calcium channels. Given as single dose in hospital."},

// ══ ANALGESICS (12) ════════════════════════════════════════════════════════
{id:"q051",topic:"Analgesics",stem:"A 19-year-old takes 24 paracetamol tablets 10 hours ago. LFTs currently normal. Treatment?",options:{A:"Nothing — LFTs are normal",B:"Activated charcoal — give now",C:"N-acetylcysteine IV",D:"Naloxone",E:"Flumazenil"},answer:"C",explanation:"N-acetylcysteine (NAC) is given for paracetamol overdose — precursor to glutathione, which detoxifies NAPQI (the toxic metabolite). Give even if LFTs normal — hepatotoxicity peaks at 72h. Activated charcoal is only useful within 1h."},
{id:"q052",topic:"Analgesics",stem:"An elderly patient with a peptic ulcer needs pain relief for osteoarthritis. Safest approach?",options:{A:"High-dose ibuprofen alone",B:"Naproxen without gastroprotection",C:"Etoricoxib (selective COX-2) + PPI",D:"Aspirin 600mg TDS",E:"Diclofenac alone"},answer:"C",explanation:"Selective COX-2 inhibitors spare gastric COX-1 → less GI mucosal damage. PPI provides additional gastric protection. Standard NSAIDs inhibit COX-1 → ↓ protective prostaglandins → ulcers. Avoid NSAIDs entirely if possible in elderly."},
{id:"q053",topic:"Analgesics",stem:"A patient takes morphine for cancer pain and develops severe constipation. Why does tolerance NOT develop to this side effect?",options:{A:"Morphine causes intestinal hypersecretion",B:"μ-opioid receptors in gut → ↓ peristalsis; unlike CNS receptors these do not downregulate",C:"Morphine directly damages the colon",D:"Morphine blocks gut serotonin receptors",E:"Morphine causes electrolyte imbalance"},answer:"B",explanation:"Opioids act on μ-receptors throughout the gut — reducing peristalsis and increasing sphincter tone. Unlike respiratory depression and sedation, tolerance to GI effects does NOT develop. Always prescribe laxatives (e.g. senna + docusate) alongside opioids."},
{id:"q054",topic:"Analgesics",stem:"A heroin user is brought in unconscious with pinpoint pupils and respiratory rate 4. Immediate treatment?",options:{A:"Diazepam",B:"Flumazenil",C:"Naloxone",D:"N-acetylcysteine",E:"Activated charcoal"},answer:"C",explanation:"Naloxone is a competitive opioid antagonist. Given IM/IV/IN for opioid overdose — reverses respiratory depression, sedation, miosis rapidly. Short half-life (60–90 min) — may need repeat doses or infusion if long-acting opioids involved."},
{id:"q055",topic:"Analgesics",stem:"A patient on an SSRI is prescribed tramadol for moderate pain. Key risk?",options:{A:"Additive nephrotoxicity",B:"Serotonin syndrome",C:"Increased bleeding risk",D:"Reduced tramadol efficacy",E:"Hypoglycaemia"},answer:"B",explanation:"Tramadol inhibits serotonin and noradrenaline reuptake. Combined with SSRIs → serotonin syndrome (agitation, hyperthermia, clonus, tachycardia). Also lowers seizure threshold. Tramadol is also a weak opioid — partial μ-receptor agonist."},
{id:"q056",topic:"Analgesics",stem:"According to the WHO analgesic ladder, what is the correct step after mild analgesics (Step 1) fail?",options:{A:"Step straight to strong opioids (Step 3)",B:"Add a weak opioid — e.g. codeine or tramadol (Step 2)",C:"Switch to an NSAID only",D:"Start adjuvant therapy only",E:"Refer for surgery immediately"},answer:"B",explanation:"WHO pain ladder: Step 1 = non-opioids (paracetamol, NSAIDs) → Step 2 = weak opioids (codeine, tramadol) ± non-opioids → Step 3 = strong opioids (morphine, fentanyl). Adjuvants can be added at any step."},
{id:"q057",topic:"Analgesics",stem:"Gabapentin is prescribed for neuropathic pain. Mechanism?",options:{A:"NMDA receptor antagonist",B:"COX-2 inhibitor",C:"Voltage-gated calcium channel alpha-2-delta subunit blocker",D:"Serotonin reuptake inhibitor",E:"Sodium channel blocker"},answer:"C",explanation:"Gabapentin and pregabalin bind to the α2δ subunit of voltage-gated Ca²⁺ channels — reduces neuronal excitability and neurotransmitter release. Used for neuropathic pain, postherpetic neuralgia, fibromyalgia. Risk of misuse and CNS depression."},
{id:"q058",topic:"Analgesics",stem:"A patient on long-term NSAIDs develops ankle oedema and rising creatinine. Mechanism?",options:{A:"NSAIDs cause renal tubular acidosis",B:"NSAIDs block renal prostaglandins → reduce GFR and cause sodium/water retention",C:"NSAIDs are directly nephrotoxic at all doses",D:"NSAIDs compete with creatinine for secretion",E:"NSAIDs cause interstitial nephritis only"},answer:"B",explanation:"Renal prostaglandins maintain GFR, especially in low-flow states. NSAIDs inhibit COX → ↓ prostaglandins → vasoconstriction → ↓ GFR → AKI and sodium/water retention. Avoid in CKD, heart failure, and dehydration."},
{id:"q059",topic:"Analgesics",stem:"Which opioid is used in a fentanyl patch for chronic cancer pain?",options:{A:"Short-acting; only for breakthrough pain",B:"Transdermal delivery; provides 72-hour sustained release",C:"Only suitable for acute post-operative pain",D:"Not suitable for cancer pain",E:"Must be combined with oral morphine always"},answer:"B",explanation:"Fentanyl patches provide 72-hour transdermal sustained delivery — good for stable chronic pain, especially when oral route is unavailable. Takes 12–24h to reach steady state. Not for opioid-naïve patients or acute pain."},
{id:"q060",topic:"Analgesics",stem:"Codeine is ineffective in a patient after tonsillectomy. Most likely pharmacogenomic reason?",options:{A:"CYP2D6 poor metaboliser — cannot convert codeine to active morphine",B:"CYP3A4 ultra-rapid metaboliser — codeine removed too quickly",C:"P-glycoprotein overexpression",D:"COMT variant — reduced pain sensitivity",E:"UGT2B7 deficiency"},answer:"A",explanation:"Codeine is a prodrug requiring CYP2D6 to convert to morphine. Poor metabolisers (7–10% of Caucasians) get no analgesia. Conversely, ultra-rapid metabolisers can get morphine toxicity — codeine is now contraindicated post-tonsillectomy in children."},
{id:"q061",topic:"Analgesics",stem:"Ketamine is used as an adjunct analgesic in chronic pain. Primary mechanism?",options:{A:"μ-opioid receptor agonist",B:"COX inhibitor",C:"NMDA receptor antagonist",D:"GABA-A potentiator",E:"α2-adrenoceptor agonist"},answer:"C",explanation:"Ketamine is an NMDA receptor antagonist — blocks glutamate-mediated central sensitisation. Used at sub-anaesthetic doses for opioid-refractory pain and to reduce opioid tolerance. Causes dissociation and hallucinations at higher doses."},
{id:"q062",topic:"Analgesics",stem:"A patient is prescribed diclofenac for acute gout flare. Which organ system requires most monitoring with prolonged use?",options:{A:"Haematopoietic system",B:"Cardiovascular — increases MI and stroke risk",C:"Thyroid gland",D:"Adrenal cortex",E:"Bone marrow"},answer:"B",explanation:"Diclofenac (especially at higher doses) is associated with increased cardiovascular events — it preferentially inhibits COX-2 like a selective inhibitor, reducing prostacyclin (vasodilatory, anti-thrombotic) more than TXA2."},

// ══ GI (10) ═══════════════════════════════════════════════════════════════
{id:"q063",topic:"GI",stem:"A post-op patient is vomiting. Antiemetic with LEAST risk of extrapyramidal side effects?",options:{A:"Metoclopramide",B:"Prochlorperazine",C:"Domperidone",D:"Haloperidol",E:"Chlorpromazine"},answer:"C",explanation:"Domperidone does not cross the BBB — extrapyramidal side effects are minimal. Metoclopramide crosses the BBB → parkinsonism, tardive dyskinesia (especially young people and prolonged use)."},
{id:"q064",topic:"GI",stem:"A patient with hepatic encephalopathy has elevated ammonia. Most appropriate laxative?",options:{A:"Senna",B:"Macrogol",C:"Lactulose",D:"Docusate",E:"Bisacodyl"},answer:"C",explanation:"Lactulose acidifies the colon → traps NH3 as NH4+ (cannot be absorbed) → excreted in faeces. Reduces serum ammonia. Dual purpose: constipation management AND hepatic encephalopathy treatment."},
{id:"q065",topic:"GI",stem:"A patient is prescribed omeprazole for dyspepsia. Mechanism?",options:{A:"Competes with histamine at H2 receptors",B:"Forms a gel over the stomach lining",C:"Irreversibly blocks the proton pump (H+/K+ ATPase)",D:"Neutralises stomach acid",E:"Blocks gastrin receptors"},answer:"C",explanation:"PPIs irreversibly inhibit H+/K+ ATPase — the final step in gastric acid secretion. Need to be acid-activated in the secretory canaliculus. Best taken 30–60 min before food. Take 3–5 days for full effect as pump turnover occurs."},
{id:"q066",topic:"GI",stem:"Ondansetron is given for chemo-induced nausea. Mechanism?",options:{A:"D2 antagonist",B:"H1 antagonist",C:"Muscarinic antagonist",D:"5-HT3 antagonist at the CTZ and gut",E:"NK1 antagonist"},answer:"D",explanation:"Ondansetron blocks 5-HT3 receptors in the chemoreceptor trigger zone and enterochromaffin cells in gut — very effective for chemo/post-op N&V. Side effect: QT prolongation. Aprepitant (NK1 antagonist) added for highly emetogenic regimens."},
{id:"q067",topic:"GI",stem:"A patient with motion sickness needs treatment. Best drug?",options:{A:"Ondansetron",B:"Domperidone",C:"Hyoscine",D:"Metoclopramide",E:"Omeprazole"},answer:"C",explanation:"Hyoscine (scopolamine) blocks muscarinic receptors in the vestibular apparatus. Classic motion sickness drug — available as oral, buccal, or transdermal patch. Cyclizine (H1 antagonist) is an alternative."},
{id:"q068",topic:"GI",stem:"A patient with active Helicobacter pylori infection needs eradication therapy. Standard first-line triple therapy?",options:{A:"Amoxicillin + metronidazole only",B:"PPI + amoxicillin + clarithromycin for 7 days",C:"PPI alone for 4 weeks",D:"Bismuth + metronidazole only",E:"Ciprofloxacin + PPI"},answer:"B",explanation:"H. pylori triple therapy: PPI + amoxicillin + clarithromycin for 7 days (UK NICE). Quadruple therapy (add bismuth) if clarithromycin resistance suspected. Test-and-treat with urea breath test or stool antigen before endoscopy in <55s without alarm symptoms."},
{id:"q069",topic:"GI",stem:"Metoclopramide is contraindicated in Parkinson's disease. Why?",options:{A:"It causes hepatotoxicity in PD patients",B:"It is a D2 antagonist — worsens dopamine deficiency and motor symptoms",C:"It causes urinary retention in PD",D:"It interacts with levodopa causing lactic acidosis",E:"It causes QT prolongation specifically in PD"},answer:"B",explanation:"Metoclopramide is a D2 antagonist — blocks dopamine in the basal ganglia, worsening parkinsonian motor symptoms. Use domperidone for nausea in PD patients (does not cross BBB)."},
{id:"q070",topic:"GI",stem:"A patient with active Crohn's disease requires steroid-sparing therapy. Most appropriate immunomodulator?",options:{A:"Methotrexate only",B:"Azathioprine or mercaptopurine",C:"Ciclosporin",D:"Hydroxychloroquine",E:"Mycophenolate mofetil"},answer:"B",explanation:"Azathioprine/6-mercaptopurine are first-line immunomodulators for steroid-dependent/steroid-refractory Crohn's. They inhibit purine synthesis → suppress T and B cell proliferation. Check TPMT levels before starting (risk of severe myelosuppression if deficient)."},
{id:"q071",topic:"GI",stem:"A patient takes regular codeine and develops severe constipation refractory to standard laxatives. Best targeted treatment?",options:{A:"Increase fibre intake",B:"Methylnaltrexone (peripherally acting mu-opioid antagonist)",C:"IV fluids and enema only",D:"Stop all opioids immediately",E:"Add lactulose and senna only"},answer:"B",explanation:"Methylnaltrexone and naloxegol are peripherally acting mu-opioid receptor antagonists (PAMORAs) — they block opioid receptors in the gut without crossing the BBB, so they relieve opioid-induced constipation without reversing central analgesia."},
{id:"q072",topic:"GI",stem:"Sucralfate is prescribed for peptic ulceration. Mechanism?",options:{A:"H2 receptor blockade",B:"Proton pump inhibition",C:"Forms a viscous barrier over the ulcer crater, protecting it from acid",D:"Neutralises gastric acid directly",E:"Reduces gastrin secretion"},answer:"C",explanation:"Sucralfate polymerises in acid environment to form a paste that adheres to the ulcer crater — acting as a physical barrier against acid and pepsin. Does not reduce acid production. Take on an empty stomach, separated from other drugs."},

// ══ ENDOCRINE (14) ════════════════════════════════════════════════════════
{id:"q073",topic:"Endocrine",stem:"Metformin is first-line for T2DM. Who should NOT receive it?",options:{A:"Overweight patient",B:"Patient with mild hypertension",C:"Patient with eGFR <30",D:"Patient on a statin",E:"Elderly patient on no other medications"},answer:"C",explanation:"Metformin can accumulate in renal impairment → risk of lactic acidosis. Contraindicated when eGFR <30. Also hold before IV contrast and peri-operatively. Mechanism: activates AMPK → reduces hepatic gluconeogenesis, increases glucose uptake."},
{id:"q074",topic:"Endocrine",stem:"A type 2 diabetic on gliclazide is found unconscious with glucose 1.8. Why does gliclazide cause hypoglycaemia even without food?",options:{A:"Blocks glucagon release",B:"Closes K-ATP channels → depolarisation → insulin release regardless of glucose level",C:"Increases insulin sensitivity only",D:"Inhibits glucose absorption",E:"Blocks SGLT2"},answer:"B",explanation:"Sulfonylureas (gliclazide, glipizide) close ATP-sensitive K+ channels in beta cells → depolarisation → insulin release. This is GLUCOSE-INDEPENDENT — hence hypoglycaemia risk even when fasting. Unlike GLP-1 agonists or DPP-4 inhibitors (glucose-dependent)."},
{id:"q075",topic:"Endocrine",stem:"Semaglutide (Ozempic/Wegovy) — receptor target?",options:{A:"DPP-4",B:"SGLT2",C:"GLP-1 receptor",D:"Insulin receptor",E:"Glucagon receptor"},answer:"C",explanation:"Semaglutide is a GLP-1 receptor agonist → glucose-dependent insulin secretion, suppresses glucagon, delays gastric emptying, reduces appetite. Used for T2DM and weight management (Wegovy at higher dose). Side effects: nausea, cholelithiasis, pancreatitis."},
{id:"q076",topic:"Endocrine",stem:"A patient on long-term prednisolone abruptly stops taking it. Key risk?",options:{A:"Hyperthyroidism",B:"Adrenal crisis (Addisonian crisis)",C:"Hyperkalaemia",D:"Hypoglycaemia only",E:"Gout attack"},answer:"B",explanation:"Long-term corticosteroids suppress the HPA axis. Abrupt withdrawal → adrenal insufficiency — hypotension, vomiting, collapse. Always taper gradually. Patients need sick-day rules: double dose during illness."},
{id:"q077",topic:"Endocrine",stem:"Empagliflozin is given to a patient with heart failure. Mechanism?",options:{A:"Stimulates insulin secretion",B:"Blocks aldosterone receptor",C:"Inhibits SGLT2 in proximal tubule → urinary glucose excretion",D:"Activates AMPK",E:"Blocks GLP-1 receptor"},answer:"C",explanation:"SGLT2 inhibitors block glucose reabsorption in the proximal tubule → glucose excreted in urine → ↓ blood glucose and weight. Also reduces preload/afterload via osmotic diuresis. Side effects: UTIs, genital Candida, DKA (even with normal glucose in T1DM)."},
{id:"q078",topic:"Endocrine",stem:"A patient is started on levothyroxine for hypothyroidism. When should TSH be rechecked?",options:{A:"After 1 week",B:"After 6–8 weeks",C:"After 12 months only",D:"Never — clinical assessment only",E:"After 24 hours"},answer:"B",explanation:"TSH has a long half-life and is slow to respond to dose changes. Recheck 6–8 weeks after starting or any dose adjustment. Target TSH: 0.5–2.5 mU/L. Take on an empty stomach, 30 min before food, separate from calcium/iron by 4h."},
{id:"q079",topic:"Endocrine",stem:"Carbimazole is used for hyperthyroidism. Serious side effect requiring urgent stopping?",options:{A:"Hair loss",B:"Rash",C:"Agranulocytosis — risk of life-threatening infection",D:"Weight gain",E:"Bradycardia"},answer:"C",explanation:"Agranulocytosis occurs in ~0.3% of patients on carbimazole — severe reduction in neutrophils → life-threatening infections. If sore throat or fever develops, stop immediately and check FBC urgently. Propylthiouracil is an alternative."},
{id:"q080",topic:"Endocrine",stem:"A patient with T1DM is on basal-bolus insulin. They are having nocturnal hypoglycaemia. Which insulin is likely responsible?",options:{A:"Rapid-acting insulin (e.g. novorapid) given with meals",B:"Long-acting basal insulin (e.g. glargine, detemir) given at night",C:"Intermediate-acting insulin only",D:"Mixed insulin preparations",E:"Both equally likely"},answer:"B",explanation:"Nocturnal hypoglycaemia in basal-bolus regimens is typically caused by the long-acting basal insulin (glargine/detemir) being too high a dose, or given too late in the evening. Reduce the basal dose or move the injection time earlier."},
{id:"q081",topic:"Endocrine",stem:"DPP-4 inhibitors (gliptins) work by which mechanism?",options:{A:"Increasing insulin secretion glucose-independently",B:"Inhibiting DPP-4 → prevents GLP-1 breakdown → prolonged incretin effect",C:"Blocking glucagon receptors directly",D:"Reducing hepatic glucose output via AMPK",E:"Blocking intestinal glucose absorption"},answer:"B",explanation:"DPP-4 inhibitors (sitagliptin, saxagliptin) inhibit dipeptidyl peptidase-4, the enzyme that degrades GLP-1 → extends the incretin effect → glucose-dependent insulin release. Low hypoglycaemia risk, weight-neutral. Side effects: nasopharyngitis, pancreatitis (rare)."},
{id:"q082",topic:"Endocrine",stem:"A patient with type 2 diabetes has a eGFR of 40. Which drug requires dose reduction?",options:{A:"Metformin",B:"Pioglitazone",C:"Sitagliptin",D:"Repaglinide",E:"Acarbose"},answer:"C",explanation:"Most DPP-4 inhibitors (sitagliptin, alogliptin) require dose reduction in renal impairment — they are renally cleared. Linagliptin is the exception (hepatically excreted — no dose adjustment needed in CKD). Metformin: hold if eGFR <30."},
{id:"q083",topic:"Endocrine",stem:"Pioglitazone (thiazolidinedione) is contraindicated in which condition?",options:{A:"Obesity",B:"Heart failure — causes fluid retention and worsens HF",C:"Hypertension",D:"Osteoporosis — it actually strengthens bone",E:"Gout"},answer:"B",explanation:"Pioglitazone causes sodium and water retention → peripheral oedema and worsens heart failure. Also associated with increased fracture risk in women and rare bladder cancer. PPAR-γ agonist — improves insulin sensitivity."},
{id:"q084",topic:"Endocrine",stem:"A patient with Addison's disease has intercurrent illness with vomiting. Sick day rules?",options:{A:"Stop all steroids during illness",B:"Double the hydrocortisone dose; if vomiting — give IM hydrocortisone",C:"Halve the dose to avoid side effects",D:"Switch to dexamethasone only",E:"Take normal dose and monitor"},answer:"B",explanation:"Sick day rules for adrenal insufficiency: double oral hydrocortisone during febrile illness or surgery. If vomiting or unable to absorb orally → IM hydrocortisone 100mg immediately. Failure to do this → adrenal crisis → death. Patients carry an emergency kit."},
{id:"q085",topic:"Endocrine",stem:"Which diabetes drug can cause lactic acidosis as a rare but serious complication?",options:{A:"Glipizide",B:"Insulin glargine",C:"Metformin",D:"Sitagliptin",E:"Empagliflozin"},answer:"C",explanation:"Metformin inhibits complex I of the mitochondrial respiratory chain → reduces hepatic lactate clearance. Lactic acidosis is rare but life-threatening, mostly in the context of renal/hepatic impairment, hypoxia, or excessive alcohol use. Presents with abdominal pain, vomiting, tachycardia, high anion gap metabolic acidosis."},
{id:"q086",topic:"Endocrine",stem:"Insulin glargine (Lantus) differs from human insulin how?",options:{A:"It acts for 3–4 hours only",B:"It is injected IV only",C:"Modified to have a flat, peakless 24-hour action profile",D:"It must be mixed with rapid-acting insulin",E:"It stimulates glucagon release"},answer:"C",explanation:"Glargine has amino acid substitutions that cause microprecipitation at physiological pH → slow sustained absorption with no peak — mimics basal insulin secretion over ~24h. Must NOT be mixed with other insulins."},

// ══ IMMUNOLOGY (7) ════════════════════════════════════════════════════════
{id:"q087",topic:"Immunology",stem:"A patient has recurrent bacterial infections with very low IgG. Deficient immunity?",options:{A:"Innate only",B:"Cell-mediated only",C:"Humoral (antibody-mediated) immunity",D:"NK cell function",E:"Complement only"},answer:"C",explanation:"IgG is the main antibody for secondary immune responses and opsonisation. Low IgG → impaired humoral immunity → recurrent bacterial infections. Could indicate hypogammaglobulinaemia (e.g. CVID) — treat with IV immunoglobulin replacement."},
{id:"q088",topic:"Immunology",stem:"NK cells destroy virus-infected cells. How do they identify them?",options:{A:"Recognise foreign proteins on MHC class II",B:"Activated by antibody-antigen complexes only",C:"Kill cells with downregulated MHC class I ('missing self')",D:"Recognise antigens presented by B cells",E:"Require prior sensitisation like CD8 T cells"},answer:"C",explanation:"NK cells kill cells that have LOST MHC class I (viruses downregulate this to evade CD8 T cells). Normal cells display MHC I → inhibitory signal → NK cell spares them. Missing self = kill signal."},
{id:"q089",topic:"Immunology",stem:"A patient receives a kidney transplant and is started on tacrolimus. Mechanism?",options:{A:"Blocks IL-2 receptor (CD25)",B:"Inhibits calcineurin → reduces IL-2 transcription → suppresses T cell activation",C:"Blocks purine synthesis",D:"Inhibits mTOR",E:"Depletes B cells"},answer:"B",explanation:"Tacrolimus (and ciclosporin) inhibit calcineurin → prevent NFAT activation → ↓ IL-2 transcription → T cell anergy. Tacrolimus is more potent than ciclosporin. Key side effects: nephrotoxicity, hypertension, neurotoxicity, new-onset diabetes."},
{id:"q090",topic:"Immunology",stem:"Rituximab depletes B cells. Which antigen does it target?",options:{A:"CD4",B:"CD20",C:"CD8",D:"CD3",E:"PD-1"},answer:"B",explanation:"Rituximab is an anti-CD20 monoclonal antibody — CD20 is expressed on pre-B and mature B cells. Used for B cell lymphomas, RA, SLE, anti-GBM disease, and ANCA vasculitis. Risk: PML (JC virus reactivation), infusion reactions, immunosuppression."},
{id:"q091",topic:"Immunology",stem:"A patient with RA is started on adalimumab. Mechanism?",options:{A:"Inhibits IL-6 signalling",B:"Blocks TNF-alpha",C:"Depletes B cells",D:"Inhibits T cell co-stimulation",E:"Blocks IL-17"},answer:"B",explanation:"Adalimumab is a fully human anti-TNF-α monoclonal antibody. TNF-α drives synovial inflammation in RA. Screen for latent TB before starting (reactivation risk). Other anti-TNFs: etanercept, infliximab, certolizumab."},
{id:"q092",topic:"Immunology",stem:"Before starting biological therapy for RA, what must be excluded?",options:{A:"Iron deficiency anaemia",B:"Latent tuberculosis infection",C:"Vitamin D deficiency",D:"Osteoporosis",E:"Hypertension"},answer:"B",explanation:"Anti-TNF therapy can reactivate latent TB — screen with IGRA (Quantiferon) and CXR before starting. If latent TB confirmed, treat with isoniazid prophylaxis before biological therapy. Absolute contraindications: active infections, active TB."},
{id:"q093",topic:"Immunology",stem:"A type 1 diabetic develops thyroid disease. What underlying mechanism links these conditions?",options:{A:"Both caused by T cell destruction of hormone-producing cells — autoimmunity",B:"Insulin causes thyroid stimulation",C:"Both are X-linked recessive",D:"Both are caused by the same viral infection",E:"They are unrelated coincidences"},answer:"A",explanation:"Type 1 DM and autoimmune thyroid disease (Hashimoto's/Graves') are both T cell-mediated autoimmune conditions — often co-exist (polyautoimmunity). Both associated with HLA-DR3/DR4. Patients with T1DM should have TFTs checked regularly."},

// ══ PHARMACOLOGY PRINCIPLES (11) ══════════════════════════════════════════
{id:"q094",topic:"Pharmacology",stem:"Drug A achieves 50% max effect at 10mg. Drug B needs 100mg. Which has higher potency?",options:{A:"Drug A has higher efficacy",B:"Drug B has higher potency",C:"Drug A has higher potency",D:"Both equal potency",E:"Drug B has higher affinity"},answer:"C",explanation:"Potency = dose needed for 50% maximum effect (EC50). Lower EC50 = more potent. Drug A needs less drug for the same effect → more potent. Potency ≠ efficacy (maximum achievable effect)."},
{id:"q095",topic:"Pharmacology",stem:"A partial agonist at full receptor occupancy cannot produce the maximum response. Why?",options:{A:"Low receptor affinity",B:"High potency prevents full activation",C:"Submaximal intrinsic efficacy (cannot fully activate the receptor)",D:"Allosteric modulation",E:"Inverse agonism"},answer:"C",explanation:"Efficacy = ability to activate a receptor once bound. Partial agonists have submaximal efficacy — even occupying 100% of receptors, they produce less than the maximum response. In the presence of a full agonist, a partial agonist acts as an antagonist."},
{id:"q096",topic:"Pharmacology",stem:"A patient overuses salbutamol and notices it works less well. Mechanism?",options:{A:"CYP induction speeds metabolism",B:"Receptor upregulation",C:"Receptor desensitisation/downregulation",D:"Drug becomes chemically inactive",E:"Antibody formation"},answer:"C",explanation:"Repeated agonist stimulation → receptor desensitisation (phosphorylation → G-protein uncoupling) then downregulation (receptor internalisation/degradation). This is tolerance — the molecular basis of SABA overuse in asthma."},
{id:"q097",topic:"Pharmacology",stem:"Which drug class targets an ENZYME as primary mechanism?",options:{A:"Beta blockers",B:"Calcium channel blockers",C:"ACE inhibitors",D:"Opioids",E:"Benzodiazepines"},answer:"C",explanation:"ACE inhibitors inhibit the angiotensin-converting enzyme. Other enzyme targets: statins (HMG-CoA reductase), PPIs (H+/K+ ATPase), aspirin (COX), trimethoprim (DHFR), allopurinol (xanthine oxidase)."},
{id:"q098",topic:"Pharmacology",stem:"A drug has a volume of distribution (Vd) of 400L in a 70kg person. What does this suggest?",options:{A:"Drug is confined to plasma (3L)",B:"Drug is mostly in extracellular fluid (14L)",C:"Drug is widely distributed into tissues",D:"Drug has high protein binding in plasma only",E:"Drug cannot cross cell membranes"},answer:"C",explanation:"Vd = apparent volume to account for total drug distribution. Plasma ≈ 3L, total body water ≈ 42L. Vd >100L indicates the drug is extensively distributed into tissues (often due to lipophilicity or tissue binding). High Vd → long half-life."},
{id:"q099",topic:"Pharmacology",stem:"A drug has a half-life of 12 hours. How long until steady state is reached with regular dosing?",options:{A:"12 hours",B:"24 hours",C:"Approximately 4–5 half-lives (48–60 hours)",D:"7 days",E:"Varies unpredictably"},answer:"C",explanation:"Steady state is reached after approximately 4–5 half-lives regardless of dose or dosing interval — this is a pharmacokinetic constant. After 4 half-lives: ~94% of steady state. This determines when to check therapeutic drug levels."},
{id:"q100",topic:"Pharmacology",stem:"A competitive antagonist is added to a system with a full agonist. Effect on dose-response curve?",options:{A:"Shifts curve left — increased potency",B:"Shifts curve right (increased EC50) but same maximum — surmountable",C:"Reduces maximum response — non-competitive",D:"Flattens the curve completely",E:"No effect on the curve"},answer:"B",explanation:"Competitive antagonists bind the same site as the agonist reversibly. Effect is overcome by increasing agonist concentration → dose-response curve shifts RIGHT (higher EC50) but the MAXIMUM remains the same. Non-competitive antagonists reduce Emax."},
{id:"q101",topic:"Pharmacology",stem:"First-pass metabolism is most significant for which route of administration?",options:{A:"Intravenous",B:"Sublingual",C:"Transdermal",D:"Oral",E:"Intramuscular"},answer:"D",explanation:"Oral drugs undergo first-pass metabolism in the gut wall and liver before reaching systemic circulation — can drastically reduce bioavailability (e.g. GTN orally has <1% bioavailability; sublingual/transdermal bypasses this). IV, sublingual, and transdermal bypass first-pass."},
{id:"q102",topic:"Pharmacology",stem:"Phenytoin shows zero-order kinetics at therapeutic doses. Clinical implication?",options:{A:"Half-life is fixed regardless of dose",B:"Small dose increases cause disproportionately large rises in plasma levels",C:"It is excreted unchanged by the kidneys",D:"It requires no therapeutic drug monitoring",E:"Its bioavailability is unaffected by protein binding"},answer:"B",explanation:"Zero-order (saturable/Michaelis-Menten) kinetics: at therapeutic doses the elimination pathway is saturated — a small dose increase causes a large non-linear rise in plasma levels. Narrow therapeutic index + zero-order kinetics = very dangerous. Monitor phenytoin levels carefully."},
{id:"q103",topic:"Pharmacology",stem:"A drug is a CYP3A4 inducer. Co-administered with a drug metabolised by CYP3A4. Effect?",options:{A:"Increased plasma levels of the co-administered drug",B:"Decreased plasma levels — faster metabolism",C:"No effect — different CYP isoenzyme",D:"Increased toxicity of the inducer",E:"Irreversible enzyme blockade"},answer:"B",explanation:"CYP inducers (rifampicin, carbamazepine, St John's Wort, phenytoin) upregulate CYP3A4 → faster metabolism of co-administered substrates → ↓ plasma levels → potential loss of efficacy. Takes days to weeks to develop fully."},
{id:"q104",topic:"Pharmacology",stem:"Therapeutic drug monitoring (TDM) is especially important for which characteristic?",options:{A:"Drugs with wide therapeutic index",B:"Drugs that are renally cleared only",C:"Drugs with narrow therapeutic index and variable pharmacokinetics",D:"All oral medications",E:"Drugs without protein binding"},answer:"C",explanation:"TDM is most critical for narrow therapeutic index drugs with unpredictable pharmacokinetics: phenytoin, digoxin, lithium, vancomycin, gentamicin, ciclosporin, tacrolimus. Trough levels typically measured (before next dose)."},

]; // end QUESTIONS

