const TOPICS = [...new Set(QUESTIONS.map(q => q.topic))].sort();

// ══ FLASHCARDS (116) ══════════════════════════════════════════════════════
const FLASHCARDS = [

// ── Antibiotics (22) ─────────────────────────────────────────────────────
{id:"f001",topic:"Antibiotics",front:"Trimethoprim — mechanism and first-line use",back:"Inhibits dihydrofolate reductase → blocks bacterial folate synthesis. First-line for uncomplicated lower UTIs."},
{id:"f002",topic:"Antibiotics",front:"Penicillin mechanism of action",back:"Binds penicillin-binding proteins (PBPs) → inhibits transpeptidase → prevents peptidoglycan cross-linking → cell wall lysis. Bactericidal."},
{id:"f003",topic:"Antibiotics",front:"MRSA treatment of choice and why",back:"Vancomycin — binds D-Ala D-Ala on peptidoglycan precursors (different target from beta-lactams). MRSA has modified PBPs (mecA gene) that resist beta-lactams."},
{id:"f004",topic:"Antibiotics",front:"Aminoglycoside toxicities (2 key ones)",back:"Nephrotoxicity and ototoxicity (hearing loss + vestibular damage). Monitor trough and peak levels. Synergistic nephrotoxicity with vancomycin."},
{id:"f005",topic:"Antibiotics",front:"Rifampicin — main drug interaction concern",back:"Potent CYP450 inducer — reduces levels of OCP, warfarin, HIV antiretrovirals, and many others. Turns body fluids orange-red (warn patients)."},
{id:"f006",topic:"Antibiotics",front:"Metronidazole — two key interactions",back:"1. Disulfiram-like reaction with alcohol (nausea, flushing, palpitations). 2. Inhibits CYP2C9 → increases warfarin levels (↑ INR)."},
{id:"f007",topic:"Antibiotics",front:"C. diff treatment by severity",back:"Mild: metronidazole PO. Moderate/severe: oral vancomycin. Recurrent/severe: fidaxomicin. IV metronidazole if ileus prevents oral therapy."},
{id:"f008",topic:"Antibiotics",front:"Macrolide (clarithromycin/erythromycin) — key drug interaction",back:"CYP3A4 inhibitors — increase levels of statins (myopathy risk), warfarin, digoxin, theophylline. Also cause QT prolongation."},
{id:"f009",topic:"Antibiotics",front:"Doxycycline — 3 contraindications",back:"1. Children <12 years (teeth discolouration, bone growth inhibition). 2. Pregnancy. 3. Avoid with antacids/dairy (chelation reduces absorption)."},
{id:"f010",topic:"Antibiotics",front:"Flucloxacillin — use and spectrum",back:"Penicillinase-resistant penicillin. Used for MSSA infections (cellulitis, osteomyelitis, septic arthritis). NOT effective against MRSA or Gram-negatives."},
{id:"f011",topic:"Antibiotics",front:"Vancomycin 'red man syndrome' — mechanism and prevention",back:"Non-immune mast cell degranulation from rapid IV infusion → histamine release → flushing, erythema, hypotension. Prevent by infusing over ≥60 min."},
{id:"f012",topic:"Antibiotics",front:"Quinolone (ciprofloxacin) — mechanism",back:"Inhibits DNA gyrase (topoisomerase II) and topoisomerase IV → prevents DNA supercoiling/replication. Bactericidal. Active against Pseudomonas and most Gram-negatives."},
{id:"f013",topic:"Antibiotics",front:"Co-trimoxazole (TMP-SMX) — use and mechanism",back:"Trimethoprim inhibits DHFR; sulfamethoxazole inhibits DHPS — double blockade of folate pathway. First-line for PCP; used in PCP prophylaxis (CD4 <200)."},
{id:"f014",topic:"Antibiotics",front:"Chloramphenicol systemic — two serious toxicities",back:"1. Idiosyncratic aplastic anaemia (irreversible, rare). 2. Grey baby syndrome (neonates — accumulation due to immature glucuronyl transferase). Safe as eye drops."},
{id:"f015",topic:"Antibiotics",front:"Beta-lactam allergy cross-reactivity",back:"True penicillin allergy: ~1% cross-reactivity with cephalosporins (via shared beta-lactam ring). Carbapenems <1%. Aztreonam — safe except cross-reacts with ceftazidime."},
{id:"f016",topic:"Antibiotics",front:"Gentamicin — peak and trough monitoring",back:"Peak (1h post-dose): assess efficacy (aim 5–10 mg/L for OD regimen). Trough (pre-dose): assess accumulation/toxicity (aim <1 mg/L OD). Monitor U&E and audiometry."},
{id:"f017",topic:"Antibiotics",front:"Antibiotic class: 50S ribosome inhibitors",back:"Macrolides (clarithromycin, azithromycin), Chloramphenicol, Clindamycin, Linezolid. Mnemonic: MAC CLs block the 50S."},
{id:"f018",topic:"Antibiotics",front:"Antibiotic class: 30S ribosome inhibitors",back:"Aminoglycosides (gentamicin, tobramycin) and Tetracyclines (doxycycline). Both bind 30S subunit."},
{id:"f019",topic:"Antibiotics",front:"First-line antibiotic for community-acquired pneumonia (non-severe, no atypical features)",back:"Amoxicillin PO. Add clarithromycin if atypical features (Mycoplasma). Severe CAP: IV co-amoxiclav + IV clarithromycin (dual cover)."},
{id:"f020",topic:"Antibiotics",front:"Nitrofurantoin — use and important caveat",back:"Used for lower UTIs (bacteriostatic in urine). Avoid if eGFR <30 — inadequate urinary concentrations AND accumulation risk. Do NOT use for pyelonephritis."},
{id:"f021",topic:"Antibiotics",front:"Linezolid — mechanism and key interactions",back:"Inhibits 50S (binds 23S rRNA) — prevents initiation complex formation. Inhibits MAO → serotonin syndrome with SSRIs/TCAs. Avoid tyramine-rich foods. Causes myelosuppression with prolonged use."},
{id:"f022",topic:"Antibiotics",front:"Cefalexin safety in pregnancy and its class",back:"Cephalosporin — first generation. Safe in pregnancy (unlike quinolones, tetracyclines, trimethoprim in 1st trimester, nitrofurantoin near term). Used for UTI and skin infections."},

// ── Cardiovascular (24) ───────────────────────────────────────────────────
{id:"f023",topic:"Cardiovascular",front:"ACE inhibitor — mechanism and main side effect",back:"Inhibits ACE → ↓ angiotensin II → vasodilation + ↓ aldosterone. Main side effect: dry cough (bradykinin accumulation). Switch to ARB if intolerable."},
{id:"f024",topic:"Cardiovascular",front:"GTN (nitrates) — mechanism",back:"Converted to nitric oxide (NO) → activates guanylyl cyclase → ↑ cGMP → smooth muscle relaxation → venodilation → ↓ preload → ↓ cardiac work → ↓ angina."},
{id:"f025",topic:"Cardiovascular",front:"Spironolactone — mechanism and hyperkalaemia risk",back:"Aldosterone antagonist (potassium-sparing diuretic). Retains K+ → hyperkalaemia risk especially with ACE inhibitors or ARBs. Check K+ and U&E closely."},
{id:"f026",topic:"Cardiovascular",front:"Digoxin — mechanism and toxicity signs",back:"Inhibits Na/K ATPase → ↑ intracellular Na+ → ↑ intracellular Ca²+ → positive inotropy + slows AV node. Toxicity: xanthopsia, bradycardia, heart block, nausea. Hypokalaemia potentiates toxicity."},
{id:"f027",topic:"Cardiovascular",front:"Warfarin — mechanism and reversal",back:"Inhibits VKORC1 → prevents activation of clotting factors II, VII, IX, X. Reversal: vitamin K (slow), FFP or PCC (fast). INR target 2–3 (AF), 2.5–3.5 (metallic valves)."},
{id:"f028",topic:"Cardiovascular",front:"DOAC overview — examples and targets",back:"Apixaban, rivaroxaban, edoxaban: Factor Xa inhibitors. Dabigatran: direct thrombin inhibitor. No routine monitoring needed. Reversal: idarucizumab (dabigatran), andexanet alfa (Xa inhibitors)."},
{id:"f029",topic:"Cardiovascular",front:"Beta-blocker — classes and cardioselective examples",back:"Class II antiarrhythmic. Cardioselective (β1): bisoprolol, metoprolol, atenolol. Non-selective (β1+β2): propranolol, carvedilol. Non-selective contraindicated in asthma."},
{id:"f030",topic:"Cardiovascular",front:"Furosemide — mechanism, uses, side effects",back:"Loop diuretic — inhibits Na/K/2Cl in thick ascending loop of Henle. Used for: acute pulmonary oedema, HF, hypertension. Side effects: hypokalaemia, dehydration, ototoxicity, hyperuricaemia."},
{id:"f031",topic:"Cardiovascular",front:"Statin — mechanism and toxicity monitoring",back:"HMG-CoA reductase inhibitors → ↓ hepatic cholesterol synthesis. Toxicity: myopathy (check CK), hepatotoxicity (LFTs). Rhabdomyolysis risk with fibrates, macrolides, ciclosporin."},
{id:"f032",topic:"Cardiovascular",front:"Amiodarone — multiple side effects (PILES mnemonic)",back:"P-Pulmonary fibrosis, I-Iodine thyroid (hypo+hyper), L-Liver toxicity, E-Eyes (corneal microdeposits), S-Skin (photosensitivity, grey-blue discolouration). Long half-life (~50 days)."},
{id:"f033",topic:"Cardiovascular",front:"Clopidogrel — mechanism, prodrug status, monitoring",back:"P2Y12 ADP receptor antagonist → irreversibly inhibits platelet aggregation. Prodrug: requires CYP2C19 activation. No routine monitoring but note interactions with PPIs (especially omeprazole)."},
{id:"f034",topic:"Cardiovascular",front:"Calcium channel blockers — two classes and key uses",back:"Dihydropyridines (amlodipine, nifedipine): vasodilate → hypertension, angina. Rate-limiting (verapamil, diltiazem): slow AV node → rate control in AF/SVT. Never combine verapamil + beta-blocker (complete heart block)."},
{id:"f035",topic:"Cardiovascular",front:"Thiazide diuretics — mechanism and contraindication",back:"Inhibit Na/Cl cotransporter in DCT → diuresis. Side effects: hypokalaemia, hyperuricaemia (gout — contraindicated), hyperglycaemia, hyponatraemia. First-line hypertension in elderly."},
{id:"f036",topic:"Cardiovascular",front:"RAAS axis — full pathway and drug targets",back:"Angiotensinogen → (renin) → Ang I → (ACE) → Ang II → AT1 receptor → vasoconstriction + aldosterone. Targets: ACE inhibitors, ARBs, renin inhibitors (aliskiren), aldosterone antagonists (spironolactone)."},
{id:"f037",topic:"Cardiovascular",front:"Protamine sulphate — use and mechanism",back:"Reverses heparin — positively charged, binds negatively charged heparin chains, forming an inactive complex. 1mg per 100 units UFH. Only partially reverses LMWH (~60%)."},
{id:"f038",topic:"Cardiovascular",front:"Lidocaine — class and use",back:"Class Ib antiarrhythmic — sodium channel blocker (fast dissociation). IV for VT/VF, especially post-MI. Also used as local anaesthetic (blocks Na+ channels in nerve membranes)."},
{id:"f039",topic:"Cardiovascular",front:"Ivabradine — mechanism and use",back:"Blocks HCN (funny If) channels in the SA node → reduces heart rate without affecting contractility or BP. Used for HFrEF (when HR >70 on max beta-blocker) and stable angina."},
{id:"f040",topic:"Cardiovascular",front:"Ezetimibe — mechanism",back:"Inhibits Niemann-Pick C1-Like 1 (NPC1L1) transporter in small intestine → reduces cholesterol absorption. Used as add-on to statin or alone if statin intolerant. Reduces LDL ~15–20%."},
{id:"f041",topic:"Cardiovascular",front:"Sodium nitroprusside — use and toxic metabolite",back:"Ultra short-acting vasodilator (IV) for hypertensive emergency. Metabolised to cyanide → cyanide toxicity with prolonged use (acidosis, confusion). Monitor thiocyanate levels."},
{id:"f042",topic:"Cardiovascular",front:"Heparin — UFH vs LMWH difference",back:"Both activate antithrombin III → inhibit thrombin and Xa. LMWH (enoxaparin) preferentially inhibits Xa. UFH inhibits both. UFH reversible with protamine; LMWH only partial. UFH used in renal failure and when rapid reversal needed."},
{id:"f043",topic:"Cardiovascular",front:"Sacubitril/valsartan (Entresto) — mechanism",back:"ARNI — ARB (valsartan) + neprilysin inhibitor (sacubitril). Neprilysin inhibition prevents BNP breakdown → natriuresis, vasodilation. Used in HFrEF. Contraindicated with ACE inhibitors (angioedema risk) — 36h washout needed."},
{id:"f044",topic:"Cardiovascular",front:"Adrenaline (epinephrine) — dose and use in anaphylaxis",back:"0.5mg IM (1:1000) into anterolateral thigh for anaphylaxis. Acts on α1 (vasoconstriction), β1 (inotropy), β2 (bronchodilation). IV 1:10,000 only in cardiac arrest."},
{id:"f045",topic:"Cardiovascular",front:"Ticagrelor vs clopidogrel — key differences",back:"Both P2Y12 inhibitors. Ticagrelor: reversible, direct-acting (no CYP2C19 needed), faster onset, more potent. Preferred post-ACS (PLATO trial). Side effect: dyspnoea (unique to ticagrelor — adenosine-mediated)."},
{id:"f046",topic:"Cardiovascular",front:"Glucagon — emergency use in beta-blocker overdose",back:"Activates glucagon receptors → ↑ cAMP in cardiac myocytes (bypasses blocked beta receptors) → ↑ heart rate and contractility. Given IV after atropine fails in beta-blocker OD."},

// ── Respiratory (15) ──────────────────────────────────────────────────────
{id:"f047",topic:"Respiratory",front:"SABA vs LABA — examples and uses",back:"SABA (salbutamol, terbutaline): short-acting, for acute relief. LABA (salmeterol, formoterol): long-acting, for maintenance. LABA must NEVER be used without ICS in asthma (increased mortality risk)."},
{id:"f048",topic:"Respiratory",front:"Beclomethasone inhaler — side effects and prevention",back:"Local: oral candidiasis, dysphonia. Prevent by rinsing mouth after use and using a spacer. Systemic effects (adrenal suppression, osteoporosis) at high doses."},
{id:"f049",topic:"Respiratory",front:"Tiotropium — class, mechanism, COPD use",back:"LAMA (long-acting muscarinic antagonist) — blocks M3 receptors → bronchodilation. Once daily. Reduces COPD exacerbations. Side effects: dry mouth, urinary retention, constipation (anticholinergic)."},
{id:"f050",topic:"Respiratory",front:"Theophylline — mechanism and toxicity",back:"PDE inhibitor → ↑ cAMP → bronchodilation + mild anti-inflammatory. Narrow therapeutic index. Toxicity: seizures, arrhythmias, nausea. Monitor levels. Multiple drug interactions (macrolides, quinolones, rifampicin)."},
{id:"f051",topic:"Respiratory",front:"Asthma BTS/SIGN stepwise treatment",back:"Step 1: SABA PRN → Step 2: + low-dose ICS → Step 3: + LABA (or LTRA/theophylline) → Step 4: ↑ ICS dose + additional therapy → Step 5: biologicals/oral steroids."},
{id:"f052",topic:"Respiratory",front:"Ipratropium vs tiotropium",back:"Both muscarinic antagonists. Ipratropium: SAMA, short-acting, used in acute COPD exacerbations and acute asthma (add-on). Tiotropium: LAMA, long-acting, maintenance COPD treatment."},
{id:"f053",topic:"Respiratory",front:"Montelukast — class and indications",back:"Leukotriene receptor antagonist (LTRA). Indications: step-up in asthma, aspirin-exacerbated asthma, exercise-induced asthma, allergic rhinitis. Side effect: mood changes, neuropsychiatric effects (rare)."},
{id:"f054",topic:"Respiratory",front:"Omalizumab — target and patient selection",back:"Anti-IgE monoclonal antibody. For severe persistent allergic asthma: positive skin prick test or raised specific IgE + uncontrolled on high-dose ICS + LABA. Given SC every 2–4 weeks."},
{id:"f055",topic:"Respiratory",front:"Acute severe asthma management",back:"High-flow O2, nebulised salbutamol (frequent), ipratropium nebuliser (add for severe), IV/oral prednisolone, IV magnesium sulphate if life-threatening, IV aminophylline if refractory."},
{id:"f056",topic:"Respiratory",front:"Propranolol — why contraindicated in asthma",back:"Non-selective beta-blocker blocks β2 receptors in bronchial smooth muscle → bronchoconstriction. If beta-blocker essential, use cardioselective (bisoprolol) with great caution."},
{id:"f057",topic:"Respiratory",front:"Smoking and theophylline — what happens when patient quits",back:"Smoking induces CYP1A2 → faster theophylline metabolism. Quitting reduces induction → theophylline builds up. Reduce dose on quitting to prevent toxicity."},
{id:"f058",topic:"Respiratory",front:"Salbutamol side effects",back:"Tachycardia, tremor, hypokalaemia (at high doses — especially nebulised), headache. Hypokalaemia is particularly important in acute severe asthma (already stressed patient)."},
{id:"f059",topic:"Respiratory",front:"Roflumilast — use and class",back:"PDE4 inhibitor → anti-inflammatory. Oral tablet for severe COPD (FEV1 <50%, chronic bronchitis, frequent exacerbations). Not a bronchodilator. Side effects: nausea, weight loss, depression."},
{id:"f060",topic:"Respiratory",front:"N-acetylcysteine — use in respiratory and overdose",back:"Respiratory: mucolytic in CF/COPD — breaks disulfide bonds in mucus. OD: precursor to glutathione → detoxifies NAPQI in paracetamol overdose. Given IV in OD."},
{id:"f061",topic:"Respiratory",front:"LABA safety in asthma — key rule",back:"LABAs (salmeterol, formoterol) must NEVER be used as monotherapy in asthma — increased risk of severe asthma attacks and death (confirmed in salmeterol safety trials). Always prescribe with an ICS (SMART therapy or separate inhalers)."},

// ── Analgesics (14) ───────────────────────────────────────────────────────
{id:"f062",topic:"Analgesics",front:"Paracetamol — mechanism and toxic metabolite",back:"Mechanism debated — may inhibit COX-3 centrally and activate endocannabinoid system. Hepatotoxic metabolite: NAPQI (N-acetyl-p-benzoquinone imine) — detoxified by glutathione. Overdose depletes glutathione → hepatocellular necrosis."},
{id:"f063",topic:"Analgesics",front:"N-acetylcysteine (NAC) — mechanism in paracetamol overdose",back:"Provides cysteine for glutathione synthesis → replenishes hepatic glutathione → detoxifies NAPQI. Give within 24h of overdose. Anaphylactoid reactions occur in ~15% (slow infusion, treat with antihistamine)."},
{id:"f064",topic:"Analgesics",front:"NSAID mechanism — COX-1 vs COX-2",back:"COX-1 (constitutive): produces protective gastric prostaglandins and TXA2. COX-2 (inducible): inflammation and pain. NSAIDs inhibit both → analgesia + ↓ GI mucosal protection. Selective COX-2 inhibitors (coxibs) spare COX-1."},
{id:"f065",topic:"Analgesics",front:"Opioid side effects — which ones tolerance develops to vs NOT",back:"Tolerance develops to: respiratory depression, sedation, analgesia, euphoria. Tolerance does NOT develop to: constipation, miosis. Always prescribe laxatives with opioids."},
{id:"f066",topic:"Analgesics",front:"Naloxone — mechanism, route, half-life caveat",back:"Competitive opioid receptor antagonist. Routes: IV, IM, intranasal. Half-life ~60–90 min — shorter than most opioids → may need repeat doses or infusion. Does NOT reverse benzodiazepine OD (use flumazenil)."},
{id:"f067",topic:"Analgesics",front:"WHO analgesic ladder — 3 steps",back:"Step 1: Non-opioid (paracetamol ± NSAID) → Step 2: Weak opioid (codeine, tramadol) ± non-opioid → Step 3: Strong opioid (morphine, oxycodone, fentanyl) ± non-opioid. Adjuvants at all steps."},
{id:"f068",topic:"Analgesics",front:"Tramadol — dual mechanism and drug interactions",back:"Weak μ-opioid agonist + inhibits serotonin/noradrenaline reuptake. Interactions: serotonin syndrome with SSRIs/MAOIs; lowers seizure threshold; caution with TCAs. CYP2D6 activation required."},
{id:"f069",topic:"Analgesics",front:"Gabapentin/pregabalin — mechanism and abuse potential",back:"Block α2δ subunit of voltage-gated Ca²+ channels → ↓ neuronal excitability. Used for neuropathic pain, epilepsy. Schedule 3 (CD) in UK — significant misuse potential, especially in opioid-dependent patients."},
{id:"f070",topic:"Analgesics",front:"Codeine — why avoid in children post-tonsillectomy",back:"Prodrug → CYP2D6 → morphine. Ultra-rapid metabolisers (genetic) convert too much to morphine → respiratory depression/death. Banned in UK for children <12 and post-tonsillectomy/adenoidectomy at any age."},
{id:"f071",topic:"Analgesics",front:"Fentanyl patch — key prescribing rules",back:"Not for opioid-naïve patients. Takes 12–24h to reach steady state. Apply to clean, non-hairy skin. Change every 72h. Cut patch → dose-dumping (dangerous). Remove before MRI."},
{id:"f072",topic:"Analgesics",front:"Aspirin — analgesic vs antiplatelet doses",back:"Analgesia/antipyretic: 300–900mg TDS. Antiplatelet: 75mg OD (irreversibly inhibits platelet COX-1 for platelet lifespan ~10 days). Avoid in children <16 (Reye's syndrome risk — hepatic encephalopathy)."},
{id:"f073",topic:"Analgesics",front:"Ketamine — mechanism and clinical uses",back:"NMDA receptor antagonist. Uses: procedural sedation/anaesthesia, sub-anaesthetic doses for chronic pain (especially opioid-refractory), depression (esketamine intranasal — Spravato). Causes dissociation, hallucinations, raises BP."},
{id:"f074",topic:"Analgesics",front:"Amitriptyline — use in pain and mechanism",back:"TCA used as adjuvant analgesic for neuropathic pain, fibromyalgia, migraine prophylaxis. Mechanism: inhibits Na+ channels + NE/5HT reuptake → central pain modulation. Side effects: sedation, anticholinergic, QT prolongation."},
{id:"f075",topic:"Analgesics",front:"Parecoxib/celecoxib — cardiovascular risk",back:"Selective COX-2 inhibitors → ↓ prostacyclin (anti-thrombotic) without ↓ TXA2 → pro-thrombotic state → ↑ MI/stroke risk (Vioxx withdrawal 2004). Use cautiously in cardiovascular disease."},

// ── GI (12) ───────────────────────────────────────────────────────────────
{id:"f076",topic:"GI",front:"PPI mechanism and clinical uses",back:"Irreversibly inhibit H+/K+ ATPase (proton pump) after acid-activation in canaliculus. Uses: GORD, peptic ulcer disease, H. pylori eradication, NSAID gastroprotection, Zollinger-Ellison syndrome."},
{id:"f077",topic:"GI",front:"Metoclopramide — mechanism and contraindication in PD",back:"D2 antagonist + prokinetic (5-HT4 agonist). Contraindicated in Parkinson's disease — worsens dopamine deficiency → deteriorating motor control. Use domperidone instead (doesn't cross BBB)."},
{id:"f078",topic:"GI",front:"H. pylori eradication — triple therapy",back:"PPI + amoxicillin + clarithromycin for 7 days (UK). If allergic to penicillin: PPI + clarithromycin + metronidazole. Test for eradication 4 weeks after (urea breath test or stool antigen — not serology)."},
{id:"f079",topic:"GI",front:"Laxative types and mechanisms",back:"Bulk-forming (ispaghula): ↑ stool bulk. Osmotic (lactulose, macrogol): draw water into bowel. Stimulant (senna, bisacodyl): stimulate ENS motility. Softener (docusate). Lactulose also used in hepatic encephalopathy."},
{id:"f080",topic:"GI",front:"Ondansetron — target, use, side effect",back:"5-HT3 antagonist at CTZ and peripheral gut. Used for chemotherapy-induced, radiation, and post-operative N&V. Key side effect: QT prolongation (avoid in congenital long QT, with other QT-prolonging drugs)."},
{id:"f081",topic:"GI",front:"Azathioprine — use and TPMT testing",back:"Immunomodulator for IBD (Crohn's/UC), RA, transplant. Metabolised by TPMT — check TPMT enzyme activity before starting. TPMT deficiency → severe myelosuppression. Monitor FBC regularly."},
{id:"f082",topic:"GI",front:"Mesalazine (5-ASA) — use in IBD",back:"First-line maintenance for UC (not effective in Crohn's). Mechanism: local anti-inflammatory in colonic mucosa — reduces TNF-α, prostaglandins. Side effects: nephrotoxicity (monitor U&E annually), rarely blood dyscrasias."},
{id:"f083",topic:"GI",front:"Domperidone — advantage over metoclopramide",back:"Does not cross BBB → no extrapyramidal or CNS side effects. Used for: gastroparesis, nausea in Parkinson's patients. QT prolongation risk — check ECG before use. Do not exceed 30mg/day or use >1 week (regulatory restrictions)."},
{id:"f084",topic:"GI",front:"Lactulose — two distinct uses",back:"1. Constipation: osmotic laxative — draws water into colon. 2. Hepatic encephalopathy: acidifies colon → converts NH3 to NH4+ (non-absorbable) → reduces serum ammonia. Onset ~24–48h for constipation."},
{id:"f085",topic:"GI",front:"Antacids — types and interactions",back:"Aluminium hydroxide (constipating), magnesium hydroxide (laxative), calcium carbonate. All chelate oral drugs (antibiotics, levothyroxine, bisphosphonates) — take 2 hours apart. Temporary symptom relief only."},
{id:"f086",topic:"GI",front:"Infliximab/adalimumab in IBD — pre-treatment screening",back:"Anti-TNF biologics for severe Crohn's/UC refractory to immunomodulators. Pre-treatment: screen for latent TB (IGRA), hepatitis B, check FBC. Contraindicated in active infection, heart failure."},
{id:"f087",topic:"GI",front:"Hyoscine butylbromide (Buscopan) — use and mechanism",back:"Muscarinic antagonist — reduces GI smooth muscle spasm. Used for IBS abdominal cramps, renal/biliary colic, and dying patients (reduces secretions). Systemic anticholinergic side effects minimal (poor BBB penetration)."},

// ── Endocrine (16) ────────────────────────────────────────────────────────
{id:"f088",topic:"Endocrine",front:"Metformin — mechanism and safe use limits",back:"Activates AMPK → ↓ hepatic gluconeogenesis, ↑ peripheral glucose uptake. Hold if eGFR <30, before IV contrast, or day of surgery. Causes lactic acidosis (rare) — especially in hypoxia/renal impairment."},
{id:"f089",topic:"Endocrine",front:"Sulfonylurea — mechanism and hypoglycaemia",back:"Close K-ATP channels in beta cells → depolarisation → insulin release (glucose-INDEPENDENT). Hypoglycaemia risk: always present, especially in elderly and renal impairment. Prescribe with meals."},
{id:"f090",topic:"Endocrine",front:"GLP-1 receptor agonists — examples and key benefits",back:"Semaglutide, liraglutide, dulaglutide. Glucose-dependent insulin secretion, ↓ glucagon, ↓ appetite, ↑ satiety, weight loss. Cardiovascular benefit (LEADER, SUSTAIN-6 trials). Side effects: nausea, pancreatitis, gallstones, thyroid C-cell tumours (rodents)."},
{id:"f091",topic:"Endocrine",front:"SGLT2 inhibitors — mechanism and non-glycaemic benefits",back:"Block SGLT2 in proximal tubule → glycosuria. Benefits beyond glucose: ↓ HF hospitalisations, ↓ CKD progression, weight loss, ↓ BP. Risks: UTI, genital Candida, DKA (euglycaemic in T1DM), Fournier's gangrene."},
{id:"f092",topic:"Endocrine",front:"DPP-4 inhibitors — examples and renal considerations",back:"Sitagliptin, saxagliptin, alogliptin: renally cleared → dose reduce in CKD. Linagliptin: hepatically excreted → no dose adjustment. Weight neutral, low hypo risk. Side effects: nasopharyngitis, pancreatitis (rare), heart failure (saxagliptin)."},
{id:"f093",topic:"Endocrine",front:"Insulin types — rapid, short, intermediate, long-acting",back:"Rapid (NovoRapid/Humalog): onset 15 min, peaks 1–2h, duration 3–5h. Short (Actrapid): onset 30 min. Intermediate (isophane/NPH): peaks 4–12h. Long-acting (glargine, detemir): 20–24h, peakless."},
{id:"f094",topic:"Endocrine",front:"Carbimazole — mechanism and agranulocytosis warning",back:"Inhibits TPO (thyroid peroxidase) → blocks iodine organification → ↓ T3/T4 synthesis. Agranulocytosis in ~0.3% — stop immediately if sore throat/fever; check FBC urgently. Also causes teratogenicity (choanal atresia) — switch to PTU in 1st trimester."},
{id:"f095",topic:"Endocrine",front:"Levothyroxine — timing and drug interactions",back:"Take on an empty stomach, 30 min before food. Separate from: calcium, iron, antacids (chelation reduces absorption). Start low, titrate slowly in elderly/ischaemic heart disease. Recheck TSH after 6–8 weeks."},
{id:"f096",topic:"Endocrine",front:"Prednisolone long-term — bone protection",back:"Corticosteroids → ↓ osteoblast activity, ↓ calcium absorption, ↑ renal calcium excretion → osteoporosis. Prescribe calcium + vitamin D from day 1 if >3 months of use. Consider bisphosphonate (alendronate) if prolonged or high-dose."},
{id:"f097",topic:"Endocrine",front:"HPA axis suppression — sick day rules",back:"Long-term steroid users cannot mount normal cortisol stress response. Sick day rules: double dose during febrile illness. If vomiting → IM hydrocortisone 100mg immediately. Risk of Addisonian crisis = death if untreated."},
{id:"f098",topic:"Endocrine",front:"Pioglitazone — PPAR-γ agonist, contraindications",back:"PPAR-γ agonist → improves insulin sensitivity (mainly muscle/fat). Contraindicated in: heart failure (fluid retention), bladder cancer (increased risk), osteoporosis (↑ fracture risk in women). Causes weight gain."},
{id:"f099",topic:"Endocrine",front:"Exenatide vs semaglutide — route and frequency",back:"Exenatide: SC twice daily (Byetta) or once weekly (Bydureon). Liraglutide: SC once daily. Semaglutide: SC once weekly (Ozempic) or daily oral (Rybelsus) or once weekly high-dose SC for obesity (Wegovy)."},
{id:"f100",topic:"Endocrine",front:"Desmopressin — uses",back:"Synthetic ADH (vasopressin) analogue. Uses: cranial diabetes insipidus (vasopressin deficiency), nocturnal enuresis, von Willebrand disease type 1 (releases vWF), haemophilia A (releases factor VIII). Risk: hyponatraemia."},
{id:"f101",topic:"Endocrine",front:"Octreotide — uses",back:"Somatostatin analogue — inhibits GH, glucagon, insulin, gastrin secretion. Uses: acromegaly, carcinoid syndrome (flushing), oesophageal varices (reduces portal pressure), VIPoma."},
{id:"f102",topic:"Endocrine",front:"Corticosteroid equivalences",back:"Hydrocortisone 20mg ≈ prednisolone 5mg ≈ methylprednisolone 4mg ≈ dexamethasone 0.75mg. Dexamethasone: most potent, longest acting, minimal mineralocorticoid activity. Used in raised ICP and nausea (anti-emetic)."},
{id:"f103",topic:"Endocrine",front:"Fludrocortisone — use and mechanism",back:"Synthetic mineralocorticoid — binds aldosterone receptors → sodium and water retention. Used in: Addison's disease (replaces aldosterone), postural hypotension, autonomic failure. Rarely used alone — usually with hydrocortisone."},

// ── Immunology (8) ────────────────────────────────────────────────────────
{id:"f104",topic:"Immunology",front:"Tacrolimus — mechanism and key toxicity",back:"Inhibits calcineurin → prevents NFAT activation → ↓ IL-2 → T cell suppression. Toxicities: nephrotoxicity (dose-dependent), neurotoxicity, new-onset diabetes after transplant (NODAT), hypertension."},
{id:"f105",topic:"Immunology",front:"Rituximab — target, uses, risks",back:"Anti-CD20 monoclonal antibody → B cell depletion. Used for: B cell lymphomas (CHOP-R), RA, SLE, ANCA vasculitis. Risks: PML (JC virus reactivation), infusion reactions, prolonged immunosuppression (check hepatitis B before use)."},
{id:"f106",topic:"Immunology",front:"Anti-TNF biologics — examples and pre-treatment requirements",back:"Adalimumab, infliximab, etanercept, certolizumab. Screen for: latent TB (IGRA + CXR), hepatitis B, active infections. Contraindicated in: active TB, MS, moderate-severe heart failure. Monitor FBC, CRP."},
{id:"f107",topic:"Immunology",front:"Ciclosporin — mechanism, uses, toxicities",back:"Calcineurin inhibitor (same as tacrolimus). Uses: transplant rejection, RA, psoriasis, nephrotic syndrome. Toxicities: nephrotoxicity, hypertension, hypertrichosis, gingival hyperplasia, hyperlipidaemia."},
{id:"f108",topic:"Immunology",front:"Mycophenolate mofetil — mechanism and use",back:"Inhibits IMPDH → blocks de novo purine synthesis → selectively suppresses lymphocyte proliferation (T and B cells). Used in transplant rejection prevention, SLE nephritis. Side effects: GI upset, myelosuppression, teratogenic."},
{id:"f109",topic:"Immunology",front:"Vaccines — live vs inactivated, immunocompromised patients",back:"Live attenuated (MMR, BCG, yellow fever, varicella, oral typhoid): contraindicated in immunocompromised/pregnant. Inactivated/subunit (flu, hepatitis B, pneumococcal): safe in immunocompromised — may have ↓ response."},
{id:"f110",topic:"Immunology",front:"Mast cell stabilisers — cromoglicate, ketotifen",back:"Stabilise mast cell membranes → prevent degranulation → ↓ histamine/leukotriene release. Sodium cromoglicate: prophylaxis of allergic asthma and allergic conjunctivitis. Ketotifen: antihistamine + mast cell stabiliser."},
{id:"f111",topic:"Immunology",front:"Complement system drugs — eculizumab",back:"Anti-C5 monoclonal antibody → blocks terminal complement cascade. Used for: PNH (paroxysmal nocturnal haemoglobinuria), atypical HUS. Risk: encapsulated organism infections (Neisseria meningitidis) → vaccinate before treatment."},

// ── Pharmacology Principles (9) ───────────────────────────────────────────
{id:"f112",topic:"Pharmacology",front:"Pharmacokinetics — ADME",back:"Absorption → Distribution → Metabolism → Excretion. Vd: volume of distribution (how widely drug distributes). Clearance: rate of elimination. Half-life = 0.693 × Vd / Clearance. Steady state reached in ~4–5 half-lives."},
{id:"f113",topic:"Pharmacology",front:"Zero-order vs first-order kinetics",back:"First-order: constant FRACTION eliminated per unit time (most drugs). Zero-order (saturable): constant AMOUNT eliminated — rate does not increase with concentration (phenytoin, alcohol, high-dose aspirin). Small dose increase → large plasma level rise."},
{id:"f114",topic:"Pharmacology",front:"CYP450 inducers vs inhibitors — key examples",back:"Inducers (↓ drug levels): rifampicin, carbamazepine, phenytoin, St John's Wort, chronic alcohol. Inhibitors (↑ drug levels): erythromycin, clarithromycin, fluconazole, amiodarone, omeprazole, grapefruit juice, acute alcohol."},
{id:"f115",topic:"Pharmacology",front:"Therapeutic index — definition and narrow TI drugs",back:"Therapeutic index = toxic dose / therapeutic dose. Narrow TI drugs require TDM: lithium, digoxin, phenytoin, theophylline, vancomycin, gentamicin, tacrolimus, ciclosporin, warfarin."},
{id:"f116",topic:"Pharmacology",front:"Drug receptor types — 4 main classes",back:"1. Ion channels (ligand-gated — fast: nicotinic, GABA-A). 2. GPCRs (G-protein coupled — second messenger). 3. Enzyme-linked receptors (tyrosine kinase — insulin, growth factors). 4. Nuclear receptors (steroid hormones, thyroid hormones — slow, gene transcription)."},

]; // end FLASHCARDS
